import React, { useState } from 'react';
import './App.css';

function App() {
  const [tokenId, setTokenId] = useState('');

  const handleTokenChange = (event) => {
    setTokenId(event.target.value);
  };

  const handleSubmit = () => {
    console.log('Token ID Submitted:', tokenId);
    // Here you will later integrate the functionality to fetch and display assets
  };

  return (
    <div className="App">
      <header className="App-header">
        <input type="text" placeholder="Enter Token ID" value={tokenId} onChange={handleTokenChange} />
        <button onClick={handleSubmit}>Submit</button>
        {/* Placeholder for asset display */}
        <div id="asset-display">
          <p>Selected assets will be displayed here</p>
        </div>
      </header>
    </div>
  );
}

export default App;
